INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989508","title":"Атака на титанов. Книга 13","author":"Хадзимэ Исаяма","type":"Манга","cover":"https://s1.livelib.ru/boocover/1003171795/140/b765/Hadzime_Isayama__Ataka_na_titanov._Kniga_13.jpg","isbn":"978-5-389-16624-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"","genres":["Манга"],"annotation":"Представители мировых держав собрались в Марли, чтобы присутствовать на выступлении Уилли Тайбера, который предупреждает всех об угрозе, исходящей с острова Парадиз. Убедить мир в серьезности этой угрозы ему помогает мятежный титан Эрен Йегер, появляющийся на сцене в самый разгар выступления. Грандиозная битва атакующего титана с титаном-молотом знаменует начало новой большой войны…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-04","rating":4.5,"review":"","added":9999624,"hdCover":""},{"id":"0989507","title":"Атака на титанов. Книга 12","author":"Хадзимэ Исаяма","type":"Манга","cover":"https://s1.livelib.ru/boocover/1002955926/140/2345/Hadzime_Isayama__Ataka_na_titanov._Kniga_12.jpg","isbn":"978-5-389-15749-1","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Манга"],"annotation":"Схватка со зверотитаном позади, разведкорпус добрался до заветного тайника в родном доме Эрена. Из дневников Гриши Йегера люди узнали тайну происхождения титанов и то, что все эти мучительные годы противостояли не только им… Какие горизонты откроются человечеству, когда стены падут?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-04","rating":4.5,"review":"","added":9999623,"hdCover":""},{"id":"0989506","title":"Атака на титанов. Книга 11","author":"Хадзимэ Исаяма","type":"Манга","cover":"https://s1.livelib.ru/boocover/1002874708/140/8e95/Hadzime_Isayama__Ataka_na_titanov._Kniga_11.jpg","isbn":"978-5-389-14602-0","publisher":"Азбука","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Манга"],"annotation":"Схватка разведкорпуса с титанами близка к развязке. Эрвин и Армин жертвуют собой, чтобы Леви и Эрен смогли повергнуть противника. Но станет ли победителем тот, кто выиграет это сражение?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-04","rating":4.5,"review":"","added":9999622,"hdCover":""},{"id":"0989505","title":"Атака на титанов. Книга 10","author":"Хадзимэ Исаяма","type":"Манга","cover":"https://s1.livelib.ru/boocover/1002772232/140/907c/Hadzime_Isayama__Ataka_na_titanov._Kniga_10.jpg","isbn":"978-5-389-14257-2","publisher":"Азбука","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Манга"],"annotation":"Разведкорпус снаряжает масштабную экспедицию через земли, захваченные титанами. Эрен собирается запечатать пролом в районе Сигансины, и тогда можно будет  добраться, наконец, до тайны, сокрытой в подвале его родного дома. Но враг не дремлет и уже подготовил засаду…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4.5,"review":"","added":9999621,"hdCover":""},{"id":"0989504","title":"Атака на титанов. Потерянные девочки","author":"Хадзимэ Исаяма,Хироси Секо","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002830814/140/a67a/__Ataka_na_titanov._Poteryannye_devochki.jpg","isbn":"978-5-389-14444-6","publisher":"Азбука","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Две истории о девочках, чьи судьбы пересеклись в жестоком мире, огороженном стенами от еще более жестокого врага – титанов. Они очень разные, эти две молчуньи, Микаса Акерман и Анни Леонхарт. И идут очень разными дорогами. Но их объединяет чувство долга, утраты и желание вырваться за пределы стен.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4.5,"review":"","added":9999620,"hdCover":""},{"id":"0989503","title":"Атака на титанов. Книга 9","author":"Хадзимэ Исаяма","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002723344/140/47b2/Hadzime_Isayama__Ataka_na_titanov._Kniga_9.jpg","isbn":"978-5-389-13634-2","publisher":"Азбука","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Страшная правда о происхождении силы титана практически сломила Эрена. Он готов пожертвовать собой, но Хистория Рейсс ломает все планы и выбирает собственный путь. И тогда ее отец, Род Рейсс, пускает в ход свое последнее оружие!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4.5,"review":"","added":9999619,"hdCover":""},{"id":"0989502","title":"Атака на титанов. Книга 8","author":"Хадзимэ Исаяма","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002622460/140/226b/Hadzime_Isayama__Ataka_na_titanov._Kniga_8.jpg","isbn":"978-5-389-13612-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Разведкорпус узнал, что наследники истинного королевского рода, который хранит тайну титанов и может дать ответы на все вопросы, держатся в тени, а на троне сидит подставной король. В голове Эрвина Смита рождается дерзкий замысел. Спецотряд полиции похищает Кристу и Эрена, отряд Леви пускается в погоню за ними, а в столице строят виселицы для заговорщиков…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4.5,"review":"","added":9999618,"hdCover":""},{"id":"0989501","title":"Атака на титанов. Книга 7","author":"Хадзимэ Исаяма","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002463443/140/caca/Hadzime_Isayama__Ataka_na_titanov._Kniga_7.jpg","isbn":"978-5-389-13083-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Райнер и Бертольт, оказавшиеся ни много ни мало бронированным титаном и титаном-колоссом, попытались похитить Эрена, и забрать его, а заодно и Имир, на свою загадочную «родину». Разведкорпус бросается в отчаянную погоню и ценой невероятных усилий и огромных жертв возвращает Эрена. А Имир принимает неожиданное решение...  Вскоре после этих событий в солдатских казармах происходит жестокое преступление и разведкорпус оказывается втянут в противостояние с военной полицией. А тем временем люди в пределах стен чувствуют себя все более уязвимыми, особенно после того, как обитатели целой деревни необъяснимым образом превратились в титанов…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4.5,"review":"","added":9999617,"hdCover":""},{"id":"0989500","title":"Атака на титанов. Книга 6","author":"Хадзимэ Исаяма","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002275809/140/db84/Hadzime_Isayama__Ataka_na_titanov._Kniga_6.jpg","isbn":"978-5-389-13020-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Неожиданно для всех титаны обнаруживаются в пределах стены Роза! На поиски и ликвидацию пролома брошены все силы, но стена оказывается нетронутой, а поведение титанов порождает все больше вопросов. Бойцы 104-го курса сталкиваются с очень необычным титаном, а потом подвергаются массированной атаке, которая не оставляет шансов на спасение. Благодаря самоотверженности Имир солдаты смогли продержаться до появления Эрена и разведкорпуса, но не успели они перевести дух, как появились бронированный титан и титан-колосс – откуда их совсем не ждали…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":5,"review":"","added":9999616,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894ff","title":"Атака на титанов. Выбор без сожалений","author":"Хадзимэ Исаяма,Хикару Суруга,Ган Снарк","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002036559/140/6f3c/__Ataka_na_titanov._Vybor_bez_sozhalenij.jpg","isbn":"978-5-389-12079-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"В подземных катакомбах столицы орудуют разбойники, свои дерзкие набеги они осуществляют с помощью устройств пространственного маневрирования! В этом мастерстве главарь банды по имени Леви не уступает ветеранам разведкорпуса. И тогда лейтенант разведкорпуса Эрвин Смит предлагает банде сделку…  Этот спин-офф «Атаки на титанов» рассказывает, как Леви прошел путь от городского бродяги до величайшего воина человечества.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4,"review":"","added":9999615,"hdCover":""},{"id":"09894fe","title":"Атака на титанов. Книга 4","author":"Хадзимэ Исаяма","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001663650/140/fd9a/Hadzime_Isayama__Ataka_na_titanov._Kniga_4.jpg","isbn":"978-5-389-10419-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Разведкорпус отправляется во внешний мир, стремясь раскрыть тайну титанов, ключ к которой, возможно, хранится в подвале родного дома Эрена Йегера. Путь к этому дому лежит через земли, захваченные титанами. Опасная миссия становится совсем безнадежной, когда разведкорпус сталкивается с невероятно смышленой и ловкой женщиной-титаном. Но еще неизвестно, что представляет большую угрозу для экспедиции, – титаны или рискованный секретный план, который разработал командир разведкорпуса, бригадир Эрвин...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":5,"review":"","added":9999614,"hdCover":""},{"id":"09894fd","title":"Атака на Титанов. Книга 3","author":"Хадзимэ Исаяма","type":"Манга","cover":"https://s1.livelib.ru/boocover/1001572261/140/f03d/Hadzime_Isayama__Ataka_na_Titanov._Kniga_3.jpg","isbn":"978-5-389-10028-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графический роман","genres":["Манга"],"annotation":"С помощью Эрена, умеющего превращаться в титана, людям удается вернуть район Трост  и обезопасить стену Роза. Закрыв пробоину огромным камнем, Эрен теряет сознание, а приходит в себя в тюрьме и выдерживает допрос командира разведкорпуса Эрвина Смита. Тот принимает решение отправить экспедицию к дому отца Эрена, где, возможно, хранится тайна титанов. Но в этом непростом деле потребуется участие самого Эрена.  В экспедиции участвуют и верные друзья Эрена, Армин и Микаса. Сначала все идет более или менее гладко, но внезапно появляется невероятно быстрая женщина-титан и атакует отряд...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4.5,"review":"","added":9999613,"hdCover":""},{"id":"09894fc","title":"Атака на Титанов. Книга 2","author":"Хадзиме Исаяма","type":"Манга","cover":"https://s1.livelib.ru/boocover/1001493530/140/895f/Hadzime_Isayama__Ataka_na_Titanov._Kniga_2.jpg","isbn":"978-5-389-08577-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Манга"],"annotation":"Мир людей содрогается под сокрущающей мощью Титанов. Принеся в жертву свою свободу, человечество укрылось в обнесенных высокими стенами городах, в надежде обезопасить выживших. Но Титанам в очередной раз удалось проломить стену и ворваться в город. Многие погибли, сражаясь с чудовищами, в том числе и лучший друг Микасы, Эрен. Потрясенная известием о его смерти, Микаса теряет бдительность и оказывается в смертельной опасности, но ей на выручку внезапно приходит загадочный титан, атакующий только других титанов. Кто же он, ее таинственный спаситель?..","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4.5,"review":"","added":9999612,"hdCover":""}]');

