SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894fb","title":"Атака на Титанов. Книга 1","author":"Хадзимэ Исаяма","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001478063/140/a546/Hadzime_Isayama__Ataka_na_Titanov._Kniga_1.jpg","isbn":"978-5-389-08423-0","publisher":"Азбука","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Мир людей пал под под сокрущающей мощью Титанов. Принеся в жертву свою свободу, человечество укрылось в обнесенных высокими стенами городах, в надежде обезопасить выживших. Но в один страшный день появился колоссальный Титан, превосходящий размерами даже городские стены. И хрупкая надежда рассыпалась в прах. Вновь началась отчаянная битва за выживание.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4.5,"review":"","added":9999611,"hdCover":""},{"id":"09894fa","title":"Морелла и Убийство на Улице Морг","author":"Ричард Корбен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006072405/140/93b4/Richard_Korben__Morella_i_Ubijstvo_na_Ulitse_Morg.jpg","isbn":"978-5-9500800-5-0","publisher":"Vicious Membrane","pubDate":"2020","language":"","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Комикс «Морелла и Убийство на Улице Морг» Ричарда Корбена — адаптация бессмертной классики от издательства Dark Horse Comics — впервые на русском языке под маской Vicious Membrane.  Два рассказа под одной обложкой! Обезьяна-убийца и месть ведьмы ждут вас на страницах этих готических кошмаров Эдгара Алана По.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4,"review":"","added":9999610,"hdCover":""},{"id":"09894f9","title":"Трансформеры против Джи Ай Джо. Квинтэссенциальное издание (сборник)","author":"Том Шиоли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003403814/140/49e1/Tom_Shioli__Transformery_protiv_Dzhi_Aj_Dzho._Kvintessentsialnoe_izdanie_sbornik.jpg","isbn":"978-5-04-103744-4","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Альтернативные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"Великолепный Том Шиоли использовал все возможности своего воображения для организации невероятного путешествия с Земли на Кибертрон и обратно! Представляем вам уникальное издание, в которое входят тринадцать выпусков \"Трансформеров против Джи Ай Джо\", истории, наполненной духом Джека Кирби и весельем Тома Шиоли, а так же незабываемый спецвыпуск \"Трансформеры против Джи Ай Джо. Фильм. Официальная комикс-адаптация\".","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4,"review":"","added":9999609,"hdCover":""},{"id":"09894f8","title":"Тор. Начало","author":"Мэттью Стёрджес,Пепе Ларраз","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003012317/140/2332/__Tor._Nachalo.jpg","isbn":"978-5-04-102846-6","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Среди высоких башен Асгарда бродит юный Тор. Самый сильный, нахальный и эгоистичный бог. Но беззаботным денькам, полным стычек с гигантами и драк с троллями, неожиданно пришёл конец, ибо его завистливый брат Локи обманом заставил Тора бездумно вторгнуться на запретную для него территорию. Он был низвержен на Землю и обрёл форму смертного инвалида по имени Дональд Блейк. Но однажды смертный обрёл знание о своей истинной сущности, а с ней пришла и великая сила. И теперь у вас есть шанс заново познакомиться с поразительной историей происхождения сына Одина в этом новом графическом романе, который невероятно успешно перенёс сказ о Торе в современные реалии! В этой эпической саге, полной гротескных ледяных гигантов, яростных дев и масштабных битв, один герой должен будет решить, кем ему быть… пока от миров, кои он любит, не останется лишь пепел!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4,"review":"","added":9999608,"hdCover":""},{"id":"09894f7","title":"Росомаха. Начало 2","author":"Кирон Гиллен,Адам Куберт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002804425/140/4cce/__Rosomaha._Nachalo_2.jpg","isbn":"978-5-91339-649-5","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Росомаха","genres":["Зарубежная фантастика","Комиксы","манга","графические романы"],"annotation":"За свою короткую жизнь Логан уже успел увидеть немало страданий. Неудивительно, что мальчик, который однажды был Джеймсом Хоулеттом, стал искать убежище в замёрзшей глуши вдали от человечества. Только он и волки. Охота. Выживание. И, наконец, жизнь. Но когда трагедия навещает дом, в котором его усыновили, Логан вынужден вернуться в цивилизованный мир. И вскоре узнает, насколько он жесток. Ибо цивилизация скрывает монстров гораздо хуже тех, что обитают в дикой природе. Таких безжалостных людей, как Хьюго Хэйвершем, который будет использовать Логана в качестве циркового уродца. Таких чудовищ, как зловещий доктор Эссекс, который будет проводить неописуемые пытки во имя науки. И, что, возможно, хуже всего, такого же, как сам Логан. Такого же мутанта, чья сущность также разрывается между человеком и животным. Того, кто может стать его величайшим союзником или самым свирепым врагом. Когда Логан встречается с Виктором Кридом, рождается вражда на многие века.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":3,"review":"","added":9999607,"hdCover":""},{"id":"09894f6","title":"Росомаха. Начало","author":"Бен Экер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003134270/140/8f90/Ben_Eker__Rosomaha._Nachalo.jpg","isbn":"978-5-04-105447-2","publisher":"Эксмо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Он был диким мутантом, найденным в лесах! Его завербовали тайным агентом в секретное правительственное учреждение! Ему было суждено помочь исполнить мечту о мирном сосуществовании людей и мутантов! Узрите рождение Росомахи, того, что зовёт себя Логаном, и его путь от дикого зверя до любимого всеми члена \"Людей Икс\". Здесь вы найдёте первую масштабную стычку Логана с Халком, равно как и решающее появление Саблезуба и Вендиго. Готовьтесь к современному и забрызганному кровью пересказу истории становления когтистого канадца!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":2.5,"review":"","added":9999606,"hdCover":""},{"id":"09894f5","title":"Росомаха. Начало","author":"Пол Дженкинс,Энди Куберт,Ричард Исанов","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002804447/140/4520/__Rosomaha._Nachalo.jpg","isbn":"978-5-91339-648-8","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Росомаха","genres":["Комиксы","манга","графические романы"],"annotation":"Росомаха — один из самых популярных персонажей комиксов, участник команды \"\"Люди Икс\"\", герой знаменитого фильма. История — его происхождения долгие годы была окутана тайной. Кто он такой и почему сам ничего не знает о своем прошлом? Уникальный комикс от лучших сценаристов и художников Marvel впервые раскроет все тайны когтистого мутанта!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4.5,"review":"","added":9999605,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894f4","title":"Batman: Detective Comics Vol. 2: Arkham Knight","author":"Питер Дж. Томаси","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005904264/140/c216/Piter_Dzh._Tomasi__Batman_Detective_Comics_Vol._2_Arkham_Knight.jpg","isbn":"978-1779501646","publisher":"DC Comics","pubDate":"2019","language":"","series":"Detective Comics","genres":[],"annotation":"GOTHAM DESERVES A BETTER DARK KNIGHT.  The Batman is a cancer. A cancer that has darkened Gotham City. His reckless vigilantism endangers innocents, creates villains, and only ever begets more violence. The people deserve justice.  The Arkham Knight has come to deliver it. The Arkham Knight has an army of supporters waging war against the Dark Knight. They''ve bombed the city and beat back Batman and his allies, but their greatest coup is still to come. Can the Arkham Knight turn Batman''s family against him?  WHO IS THE ARKHAM KNIGHT?!  The people of Gotham believe their city''s hero protects them from the dangers on their streets, but is their violent, lawless vigilante really much better than the monsters he fights? This is the Arkham Knight''s Crusade: To defeat the Batman and free Gotham from the tyranny of his darkness.  The Knight has brought an entire round table of deadly allies from the asylum but is hoping to recruit one more: Damian Wayne. Can this masked renegade sway Robin to join their cause?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":2,"review":"","added":9999604,"hdCover":""},{"id":"09894f3","title":"Batman: Detective Comics Vol. 1: Mythology","author":"Питер Дж. Томаси","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005902935/140/8706/Piter_Dzh._Tomasi__Batman_Detective_Comics_Vol._1_Mythology.jpg","isbn":"978-1779501622","publisher":"DC Comics","pubDate":"2019","language":"","series":"Batman","genres":[],"annotation":"The Arkham Knight has arrived in Gotham City with an entire round table of deadly allies, and their first encounter will leave Batman shaken to his core!  AN OLD ENEMY RETURNS AND A STRANGE NEW MYSTERY BEGINS!  A mysterious enemy who knows everything about Batman''s history is pulling no punches. Clues take the form of disturbing reminders of the Dark Knight''s darkest days as he is forced to fight a losing battle to protect those who have been most important to his transformation from a scared little boy to Gotham''s champion.  When interrogating his foes inside Arkham Asylum raises more questions than answers, Batman must depend on himself alone to discover the mastermind behind these challenges...a foe who has been part of Batman''s life since the very beginning of his crime-fighting career!  The acclaimed Superman writer/artist team of Peter J. Tomasi ( Adventures of the Super Sons) and Doug Mahnke ( Justice League) pit Batman against a figure from his past who knows all the Dark Knight''s secrets!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":3.5,"review":"","added":9999603,"hdCover":""},{"id":"09894f2","title":"Batman: Detective Comics Vol. 9: Deface the Face","author":"Джеймс Робинсон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003162174/140/8539/Dzhejms_Robinson__Batman_Detective_Comics_Vol._9_Deface_the_Face.jpg","isbn":"978-1401290641","publisher":"DC Comics","pubDate":"2019","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Once upon a time, Harvey Dent was the best man in Gotham City. Now he''s two of the worst as the bifurcated criminal called Two-Face. Harvey''s devilish duality is a painful reminder of the force for good he once was as Gotham''s district attorney...and as the close friend and ally of Batman and Jim Gordon.  But when a series of double-themed crimes breaks out and a sinister terrorist organization slithers back into town, the Dark Knight must turn to Two-Face to unravel the mystery and stop the invasion.  For Harvey, it''s a chance to crack the one case he could never solve...if he can keep his dark side under control. If he wins, his unlikely partnership with Batman could pay off, and mark a turning point in his tragic life.  But when the balance between good and evil can be decided with the flip of a coin, all bets are off. Some scars run deep. And the conspiracy Batman, Gordon and Two-Face are about to uncover runs even deeper...  Comics writer James Robinson is joined by artists Stephen Segovia and Carmine Di Giandomenico for Batman: Detective Comics Vol. 9: Deface the Face--a thrilling adventure that takes the Dark Knight deep inside the mind of one of his most fascinating foes.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":2.5,"review":"","added":9999602,"hdCover":""},{"id":"09894f1","title":"Batman: Detective Comics Vol. 8: On the Outside","author":"Bryan Hill","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003162172/140/9887/Bryan_Hill__Batman_Detective_Comics_Vol._8_On_the_Outside.jpg","isbn":"978-1401285289","publisher":"DC Comics","pubDate":"2018","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"The greatest superhero team in Gotham City history is gone... this time, for good. How will the Dark Knight pick up the pieces knowing that his squad of vigilantes is gone? Find out in Batman: Detective Comics Vol. 8!  In the aftermath of the last stand of the Gotham Knights, Batman, Batwoman, Red Robin, Orphan, Azrael, Batwing and company took down a monster they helped create. How will they deal with the physical and psychological ramifications of this epic battle? And who will hang up their capes?  Duke Thomas. Cassandra Cain. They and other young heroes don''t intend to stand down, no matter what Batman thinks is best. Who can Batman trust to guide them? They need a teacher... and Black Lightning fits the bill!  The epilogue chapter to writer James Tynion IV''s acclaimed run on the series is here in Batman: Detective Comics Vol. 8!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":3,"review":"","added":9999601,"hdCover":""},{"id":"09894f0","title":"Ice Cream Man Volume 2: Strange Neapolitan","author":"У. Максвелл Принс,Мартин Мораццо,Крис О’Хэллоран","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005900217/140/78ae/__Ice_Cream_Man_Volume_2_Strange_Neapolitan.jpg","isbn":"978-1534308763","publisher":"Image Comics","pubDate":"2018","language":"Английский","series":"Ice Cream Man","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":3.5,"review":"","added":9999600,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894ef","title":"Мороженщик. Том 1. Радужная обсыпка","author":"У. Максвелл Принс,Мартин Мораццо,Крис ОХэллоран","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005516976/140/d4c3/__Morozhenschik._Tom_1._Raduzhnaya_obsypka.jpg","isbn":"978-5-04-116094-4","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"Альтернативные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"Шоколадный, ванильный, экзистенциальный ужас... Для любого несчастья есть свой вкус. \"Мороженщик\" — эталонная серия в жанре рассказов о горести, чуде и спасении. Каждая история знакомит нас с разными странными персонажами, копающимися в своей приторной порции страданий. И где-то на окраине всех этих событий, словно весёленькая музыка его яркого фургончика, стоит Мороженщик... ткач историй, продавец вкусностей. Друг. Враг. Бог. Демон. Человек, который щёлкает пальцами: раз — и готово. Теперь ваша жизнь изменится навсегда.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":3,"review":"","added":9999599,"hdCover":""},{"id":"09894ee","title":"Wonder Woman: Dead Earth","author":"Дэниел Джонсон","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005888751/140/c04b/Deniel_Dzhonson__Wonder_Woman_Dead_Earth.jpg","isbn":"978-1779502612","publisher":"DC Comics","pubDate":"2020","language":"","series":"DC Black Label","genres":[],"annotation":"Wonder Woman''s mission was to save Man''s World from itself. She failed.  When Diana awakens from a centuries-long sleep, she discovers Earth has been reduced to a nuclear wasteland. Now she''s marooned in a dark and dangerous future, protecting the last human city from titanic monsters and struggling to uncover the secret of this dead Earth...and how she may be responsible for it.  In the newest title from DC''s critically acclaimed Black Label line, Daniel Warren Johnson, the celebrated creator of Murder Falcon and Extremity, mixes sci-fi and fantasy into a harrowing postapocalyptic vision of Wonder Woman unlike anything you''ve ever seen. Collects the full four issue miniseries along with behind-the-scenes artwork. Review “ Dead Earth is what happens when you plop Diana of Themiscyra’s mythos into apocalyptian high fantasy.” —Den of Geek  “ Wonder Woman: Dead Earth throws Diana Prince into a desolate wasteland filled with monsters in an epic and dark comic series.” —Screen Rant","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":3,"review":"","added":9999598,"hdCover":""},{"id":"09894ed","title":"Dead Body Road, Volume 1","author":"Джастин Джордан","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005883711/140/56e8/Dzhastin_Dzhordan__Dead_Body_Road_Volume_1.jpg","isbn":"978-1632150479","publisher":"Image Comics","pubDate":"2014","language":"","series":"Dead Body Road","genres":[],"annotation":"Orson Gage is no good man. His wife''s death thrusts the only kind of righteousness he''s ever known upon him: Revenge! Her murderers must die. All of them! In Dead Boy Road, writer Justin Jordan (The Strange Talent of Luther Strode) and artist Matteo Scalera (Black Science) follow Gage on the dark road he''s chosen to travel ― a road that looks more and more like a highway to Hell!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":3.5,"review":"","added":9999597,"hdCover":""},{"id":"09894ec","title":"Something is Killing the Children, Vol. 3","author":"Джеймс Тайнион IV,Werther Dell’Edera","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005753391/140/aaff/__Something_is_Killing_the_Children_Vol._3.jpg","isbn":"1684157072","publisher":"Boom! Studios","pubDate":"2021","language":"Английский","series":"","genres":[],"annotation":"NOT ALL MONSTERS HIDE IN THE DARK.  Archer’s Peak is in lockdown, as Erica Slaughter has lost control of the situation and news of the killings has spread outside the town. But as the House of Slaughter arrives to clean up the situation by any means necessary, Erica will find that the true threat to those around her isn’t who - or what - she ever expected. And the cost of saving the day may be too high for anyone to pay...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4,"review":"","added":9999596,"hdCover":""},{"id":"09894eb","title":"Something is Killing the Children, Vol. 2","author":"Джеймс Тайнион IV","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005645313/140/359d/Dzhejms_Tajnion_IV__Something_is_Killing_the_Children_Vol._2.jpg","isbn":"1684156491","publisher":"Boom! Studios","pubDate":"2020","language":"Английский","series":"","genres":["Зарубежные детективы"],"annotation":"Erica Slaughter may have slain the monster terrorizing the small Wisconsin town of Archer’s Peak, but now she sets off deeper into the woods -- because the monster she killed was a mother… and now she needs to kill its children. EVIL NEVER DIES...UNLESS ERICA SLAUGHTER KILLS IT. Erica Slaughter may have slain the monster terrorizing the small Wisconsin town of Archer’s Peak, but the horror is far from over. As her mysterious handler arrives in town to clean up her mess and quarantine the townsfolk, Erica sets off deeper into the woods -- because the monster she killed was a mother… and now she needs to kill its children.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4,"review":"","added":9999595,"hdCover":""},{"id":"09894ea","title":"Something is Killing the Children, Vol. 1","author":"Джеймс Тайнион IV","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004112292/140/6153/Dzhejms_Tajnion_IV__Something_is_Killing_the_Children_Vol._1.jpg","isbn":"9781684155583","publisher":"Boom! Studios, Boom!","pubDate":"2020","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"When the children of Archer''s Peak—a sleepy town in the heart of America—begin to go missing, everything seems hopeless. Most children never return, but the ones that do have terrible stories—impossible details of terrifying creatures that live in the shadows. Their only hope of finding and eliminating the threat is the arrival of a mysterious stranger, one who believes the children and claims to be the only one who sees what they can see.  Her name is Erica Slaughter. She kills monsters. That is all she does, and she bears the cost because it must be done.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4.5,"review":"","added":9999594,"hdCover":""},{"id":"09894e9","title":"Savage Avengers Vol. 3: Enter the Dragon","author":"Джерри Дагган","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005853477/140/f9db/Dzherri_Daggan__Savage_Avengers_Vol._3_Enter_the_Dragon.jpg","isbn":"978-1302921873","publisher":"Marvel","pubDate":"2021","language":"","series":"Savage Avengers","genres":[],"annotation":"The horrific secret of Kulan Gath''s power is revealed! Steel yourself, True Believers - this one is a bummer for the ages. Can Doctor Strange and Elektra deal with this unbelievable horror? Speaking of horror, something is killing the Shuma-Goraths! That would usually be great news, but Kulan Gath thinks he''s fi nally fi gured out how to consume the Elder God - and that''s very bad news for our plane of existence! Strange and Elektra have a plan, though...and the Savage Avengers will assemble! Conan the Barbarian, Wolverine, Doctor Strange, Elektra, Black Widow, Hellstrom, Brother Voodoo, Magik...and more! The heroes draw up a last-ditch battle plan against Kulan Gath - and Conan must wield a most unexpected weapon in the fi ght against darkness!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":2.5,"review":"","added":9999593,"hdCover":""},{"id":"09894e8","title":"Savage Avengers Vol. 2: To Dine With Doom","author":"Джерри Дагган","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005853285/140/f7dd/Dzherri_Daggan__Savage_Avengers_Vol._2_To_Dine_With_Doom.jpg","isbn":"978-1302916664","publisher":"Marvel","pubDate":"2020","language":"","series":"Savage Avengers","genres":[],"annotation":"It''s the ultimate odd couple - Conan and Frank Castle! The barbarian and the Punisher are attempting to walk out of the Savage Land, hauling the caskets of Frank''s family - through Antarctica. Frank Castle was never much of a religious man, but after fighting alongside Conan, he''s becoming firmly \"Crom-curious.\" Then, Conan hates wizards - but as this strange modern-day world that he has found himself in celebrates the holidays, the Cimmerian has to deal with two famous magic wielders: Doctor Strange and Doctor Doom! Ho-ho-holy crap! Can these three set aside their differences to deal with Kulan Gath, the name on the very top of all their naughty lists?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":3,"review":"","added":9999592,"hdCover":""},{"id":"09894e7","title":"Savage Avengers Vol. 1: City of Sickles","author":"Джерри Дагган","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005853183/140/af4c/Dzherri_Daggan__Savage_Avengers_Vol._1_City_of_Sickles.jpg","isbn":"978-1302916657","publisher":"Marvel","pubDate":"2019","language":"","series":"Savage Avengers","genres":[],"annotation":"The most savage, most unkillable team of characters in the Marvel Universe is assembled! Wolverine! Venom! Elektra! Punisher! And in their midst - Conan the Barbarian! Conan has returned to the Marvel Universe, and his new adventures begin here. What is the City of Sickles? Who is the Marrow God? How is the Hand involved? The roughest and most dangerous characters rumble through this new title starting with...Conan vs. Wolverine? ''Nuff said.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4,"review":"","added":9999591,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894e6","title":"Бэтмен. Темный Рыцарь. Легенды: Образы","author":"Деннис О''Нил","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004046451/140/bbca/Dennis_O039Nil__Betmen._Temnyj_Rytsar._Legendy_Obrazy.jpg","isbn":"978-5-389-17981-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"«Образы» — аллюзия на первый выпуск серии «Бэтмен» 1940 года, который был опубликован 24 апреля. В том выпуске в одной из историй в комиксе впервые появился Джокер. Первое явление заклятого врага-друга стало настоящим испытанием для Темного Рыцаря. Переложение истории сделал Деннис О’Нил, вернув Бэтмена в то время, когда Джокер впервые бросил ему вызов. В новой версии классической истории также есть некоторые отсылки к комиксу «Бэтмен: Год Первый» Фрэнка Миллера. Джокер собрал самых выдающихся отморозков Готэма, включая своего двоюродного брата Мэлвина, чтобы провернуть крупное дельце.  С 1989 года, после успеха первого фильма Тима Бертона о Бэтмене, в DC стала выходить серия комиксов «Темный Рыцарь. Легенды». Серия сильно выделялась среди прочих комиксов о Бэтмене того периода, так как истории в ней больше походили на «Год Первый» Миллера и рассказывали в основном о ранних делах Бэтмена в начале его карьеры защитника улиц Готэма. Выпуск «Образы» вышел под номером 50, и он станет прекрасным подарком Джокеру к 80-летию со дня первого появления во вселенной DC.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4,"review":"","added":9999590,"hdCover":""},{"id":"09894e5","title":"The Manhattan Projects Volume 5: The Cold War","author":"Джонатан Хикман,Ник Питарра","type":"Книга","cover":"https://s1.livelib.ru/boocover/1004069653/140/6e9c/__The_Manhattan_Projects_Volume_5_The_Cold_War.jpg","isbn":"978-1632151841","publisher":"Image Comics","pubDate":"2015","language":"","series":"Manhattan Projects","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4,"review":"","added":9999589,"hdCover":""},{"id":"09894e4","title":"The Manhattan Projects Volume 4: The Four Disciplines","author":"Джонатан Хикман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1004069605/140/80ac/Dzhonatan_Hikman__The_Manhattan_Projects_Volume_4_The_Four_Disciplines.jpg","isbn":"978-1607069614","publisher":"Image Comics","pubDate":"2014","language":"","series":"Manhattan Projects","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4,"review":"","added":9999588,"hdCover":""},{"id":"09894e3","title":"Манхэттенские проекты. Том 3","author":"Джонатан Хикман","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002178531/140/feb7/Dzhonatan_Hikman__Manhettenskie_proekty._Tom_3.jpg","isbn":"978-5-91339-503-0","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Секретная лаборатория в Лос-Аламосе на самом деле занималась не атомной бомбой. Вернее, бомбой тоже — но это был самый скучный и обыденный из их проектов. Лучшие умы Америки (и некоторых других стран при наличии грин-карты) были нацелены на куда более важные для человечества и сложные для постижения вопросы — вроде межзвездных перелетов, искусственного интеллекта и других измерений. Но не ради прогресса человечества и американского послевоенного господства, разумеется. Нет, все, что двигало великими учеными — это их собственные великие амбиции. С самими «светилами науки» все было так же непросто, как и с их работой — Оппенгеймер на самом деле был маньяком-каннибалом с расщеплением личности (но это вовсе не Роберт, который погиб до того, как смог попасть на Манхэттенский проект, а его брат-близнец Джозеф), Эйнштейна заменил его двойник из параллельной вселенной, а Гарри Даглян выжил после аварии, но теперь представляет из себя радиоактивный скелет внутри специального костюма. Все эти люди больше всего остального ценили науку — что, в частности, означает, что жизни других людей и абстрактные этические вопросы они ценили гораздо меньше.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":4,"review":"","added":9999587,"hdCover":""},{"id":"09894e2","title":"Манхэттенские проекты. Том 2","author":"Джонатан Хикман,Ник Питарра","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001465649/140/bad0/__Manhettenskie_proekty._Tom_2.jpg","isbn":"978-5-91339-348-7","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В лаборатории в Лос-Алсмос лучшие умы человечества - ученые с мировым именем Эйнштейн, Оппенгеймер, Ферми, Фейнман, Фон Браун, Даглян - трудятся над строго засекреченной программой \"Манхэттенские проекты\". Официально работа ведется над разработкой атомной бомбы, но на самом деле все значительно сложнее и запутаннее. Да с учеными все не так просто. Энрико Ферми (автор парадокса, ставящего под сомнение существование внеземной жизни) оказывается инопланетянином, физик-теоретик Оппенгеймер — маньяком-каннибалом с расщеплением личности, а Эйнштейн — алкоголиком. \"Манхэттенские проекты\" - это кровожадная, невероятно увлекательная и дико смешная альтернативная история 40-х годов прошлого века, в которой круто замешаны наука, внеземные цивилизации, политика и военные авторства Джонатана Хикмана, создателя \"Восток Запада\", \"Infinity\", \"Secret Wars\", \"FF\" и множества других.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":3.5,"review":"","added":9999586,"hdCover":""},{"id":"09894e1","title":"Манхэттенские проекты. Том 1","author":"Джонатан Хикман,Ник Питарра","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001388607/140/8f54/__Manhettenskie_proekty._Tom_1.jpg","isbn":"978-5-91339-321-0","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В лаборатории в Лос-Алсмос лучшие умы человечества - ученые с мировым именем Эйнштейн, Оппенгеймер, Ферми, Фейнман, Фон Браун, Даглян - трудятся над строго засекреченной программой \"Манхэттенские проекты\". Официально работа ведется над разработкой атомной бомбы, но на самом деле все значительно сложнее и запутаннее. Да с учеными все не так просто. Энрико Ферми (автор парадокса, ставящего под сомнение существование внеземной жизни) оказывается инопланетянином, физик-теоретик Оппенгеймер — маньяком-каннибалом с расщеплением личности, а Эйнштейн — алкоголиком. \"Манхэттенские проекты\" - это кровожадная, невероятно увлекательная и дико смешная альтернативная история 40-х годов прошлого века, в которой круто замешаны наука, внеземные цивилизации, политика и военные авторства Джонатана Хикмана, создателя \"Восток Запада\", \"Infinity\", \"Secret Wars\", \"FF\" и множества других.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":3.5,"review":"","added":9999585,"hdCover":""}]');
